1142→router.post('/update-username', requireAuth, async (req, res) => {
1143→    const userId = req.userId;
1144→    const { username } = req.body;
1145→
1146→    if (!username || typeof username !== 'string') {
1147→        return res.status(400).json({ error: 'username is required' });
1148→    }
1149→
1150→    const trimmed = username.trim();
1151→    if (trimmed.length < 3 || trimmed.length > 50) {
1152→        return res.status(400).json({ error: 'username must be 3-50 characters' });
1153→    }
1154→
1155→    if (!/^[a-zA-Z0-9-]+$/.test(trimmed)) {
1156→        return res.status(400).json({ error: 'username can only contain letters, numbers, and hyphens' });
1157→    }
1158→
1159→    const normalized = trimmed.toLowerCase();
1160→    const RESERVED_WORDS = ['admin', 'root', 'iskrib', 'iskryb', 'support', 'help', 'api', 'www', 'null', 'undefined'];
1161→    if (RESERVED_WORDS.includes(normalized)) {
1162→        return res.status(400).json({ error: 'this username is reserved' });
1163→    }
1164→
1165→    // Check uniqueness
1166→    const { data: existing } = await supabase
1167→        .from('users')
1168→        .select('id')
1169→        .ilike('username', normalized)
1170→        .neq('id', userId)
1171→        .limit(1);
1172→
1173→    if (existing && existing.length > 0) {
1174→        return res.status(409).json({ error: 'username is already taken' });
1175→    }
1176→
1177→    const { error: updateError } = await supabase
1178→        .from('users')
1179→        .update({ username: trimmed.toLowerCase() })
1180→        .eq('id', userId);
1181→
1182→    if (updateError) {
1183→        console.error('update-username error:', updateError.message);
1184→        return res.status(500).json({ error: 'failed to update username' });
1185→    }
1186→
1187→    return res.status(200).json({ message: 'success', username: trimmed.toLowerCase() });
1188→});
