 1→import { useEffect } from 'react';
 2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
 3→import { $createParagraphNode, $getRoot, $getSelection, $isRangeSelection, COMMAND_PRIORITY_EDITOR } from 'lexical';
 4→import { $createImageNode, INSERT_IMAGE_COMMAND } from '../ImageNode';
 5→import { $createHeadingNode } from '@lexical/rich-text';
 6→
 7→export default function ImagePlugin({addUploadedImagePath}) {
 8→  const [editor] = useLexicalComposerContext();
 9→
10→  useEffect(() => {
11→    return editor.registerCommand(
12→      INSERT_IMAGE_COMMAND,
13→      (payload) => {
14→        const { src, width, height, loading = false} = payload;
15→
16→        // only track uploaded paths for non-loading (already uploaded) images
17→        if (!loading) {
18→          const filePath = src.split('/journal-images/').pop();
19→          if(filePath){
20→            addUploadedImagePath(filePath)
21→          } else {
22→            console.warn('Could not extract filePath from src:', src);
23→          }
24→        }
25→
26→        const imageNode = $createImageNode(src, width, height, loading);
27→        const paragraphNode = $createParagraphNode();
28→        const selection = $getSelection();
29→        
30→        if($isRangeSelection(selection)){
31→           selection.insertNodes([imageNode]);
32→        }else {
33→          const root = $getRoot();
34→          root.append(imageNode)
35→          root.append(paragraphNode)
36→        }
37→        
38→       
39→
40→        return true;
41→      },
42→      COMMAND_PRIORITY_EDITOR
43→    );
44→  }, [editor]);
45→
46→  return null;
47→}

