## 7. Paragraph ID Injection Utility (Server-Side)

```javascript
// server/utils/paragraphIdUtils.js
import { nanoid } from 'nanoid';

/**
 * Walk the Lexical JSON tree and assign stable paragraphId
 * to every paragraph, heading, and quote node that lacks one.
 * Mutates the object in place and returns it.
 */
export function assignParagraphIds(lexicalJson) {
    if (!lexicalJson?.root?.children) return lexicalJson;

    for (const child of lexicalJson.root.children) {
        if (['paragraph', 'heading', 'quote'].includes(child.type)) {
            if (!child.paragraphId) {
                child.paragraphId = nanoid(8);
            }
        }
    }

    return lexicalJson;
}

/**
 * Extract all paragraphIds from a Lexical JSON tree.
 * Returns an array of { index, paragraphId, textPreview }.
 */
export function extractParagraphIds(lexicalJson) {
    if (!lexicalJson?.root?.children) return [];

    const result = [];
    let idx = 0;

    for (const child of lexicalJson.root.children) {
        if (['paragraph', 'heading', 'quote'].includes(child.type)) {
            const textNodes = child.children?.filter(c => c.type === 'text') || [];
            const text = textNodes.map(c => c.text).join(' ').slice(0, 50);
            result.push({
                index: idx,
                paragraphId: child.paragraphId || null,
                textPreview: text,
            });
            idx++;
        }
    }

    return result;
}
```

This would be called in the save-journal flow within `uploadService.js` or the controller, right before the content is stored:

```javascript
// In the save/update journal flow
const contentObj = JSON.parse(content);
assignParagraphIds(contentObj);
const contentWithIds = JSON.stringify(contentObj);
// ... store contentWithIds in the database
```

